import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"LLM 路由演算法：工業案例與量化數據","description":"","frontmatter":{"title":"LLM 路由演算法：工業案例與量化數據","type":"documentation"},"headers":[],"relativePath":"research/agent-harness/llm-routing-industrial-cases.md","filePath":"research/agent-harness/llm-routing-industrial-cases.md","lastUpdated":1779894392000}'),l={name:"research/agent-harness/llm-routing-industrial-cases.md"};function o(i,t,h,s,d,u){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="llm-路由演算法-工業案例與量化數據" tabindex="-1">LLM 路由演算法：工業案例與量化數據 <a class="header-anchor" href="#llm-路由演算法-工業案例與量化數據" aria-label="Permalink to &quot;LLM 路由演算法：工業案例與量化數據&quot;">​</a></h1><blockquote><p>建立日期：2026-05-08 研究方法：autoresearch + web search（基於 AgentOpt 論文延伸） 關聯論文：<code>../papers/2026-04-07-agentopt-client-side-optimization.md</code></p></blockquote><hr><h2 id="核心命題" tabindex="-1">核心命題 <a class="header-anchor" href="#核心命題" aria-label="Permalink to &quot;核心命題&quot;">​</a></h2><p>AgentOpt（arxiv 2604.06296）證明「弱規劃器 + 強求解器」優於單一強模型（31.71% → 74.27%）。 本文追蹤<strong>工業界如何實作此概念</strong>，以及除 UCB-E 外的路由演算法實際部署情況。</p><hr><h2 id="_1-routellm-lmsys-iclr-2025" tabindex="-1">1. RouteLLM（LMSYS, ICLR 2025） <a class="header-anchor" href="#_1-routellm-lmsys-iclr-2025" aria-label="Permalink to &quot;1. RouteLLM（LMSYS, ICLR 2025）&quot;">​</a></h2><p><strong>來源：</strong> <a href="https://arxiv.org/abs/2406.18665" target="_blank" rel="noreferrer">https://arxiv.org/abs/2406.18665</a></p><h3 id="核心設計" tabindex="-1">核心設計 <a class="header-anchor" href="#核心設計" aria-label="Permalink to &quot;核心設計&quot;">​</a></h3><p>以偏好數據（Chatbot Arena）訓練的<strong>輕量路由器</strong>，對每個 query 判斷是否需要強模型（GPT-4）或可用弱模型（Mixtral 8x7B）。</p><h3 id="量化結果-三個數字的分母不同-需區分" tabindex="-1">量化結果（三個數字的分母不同，需區分） <a class="header-anchor" href="#量化結果-三個數字的分母不同-需區分" aria-label="Permalink to &quot;量化結果（三個數字的分母不同，需區分）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>路由器類型</th><th>達成 GPT-4 95% 性能所需 GPT-4 呼叫比例</th><th>相較隨機基準成本節省</th></tr></thead><tbody><tr><td>Matrix Factorization（Arena 數據）</td><td>26%</td><td>~48%</td></tr><tr><td>Matrix Factorization（+LLM judge 增強）</td><td><strong>14%</strong></td><td><strong>75%</strong></td></tr><tr><td>Causal LLM（MMLU，augmented）</td><td>54%</td><td>14%</td></tr></tbody></table><blockquote><p>⚠️ 數字說明（防混淆）：</p><ul><li><strong>14% GPT-4 呼叫</strong>：衡量路由器將多少 query 送至強模型（越低越好）</li><li><strong>75% cheaper than random baseline</strong>：以「所有 query 隨機分配」作分母</li><li><strong>「85% cost reduction」</strong>（部分部落格引用）：以「所有 query 送 GPT-4」作分母；這是二手來源的綜合數字，原始論文表述為「over 85%」on MT Bench</li><li>三者描述同一個路由器，但起點不同，<strong>不可互換引用</strong></li></ul></blockquote><p><strong>相較商業路由器（Chatbot Arena 商業方案）：</strong> 相同性能，<strong>便宜 40%+</strong></p><h3 id="遷移學習特性" tabindex="-1">遷移學習特性 <a class="header-anchor" href="#遷移學習特性" aria-label="Permalink to &quot;遷移學習特性&quot;">​</a></h3><p>路由器在<strong>強/弱模型改變時仍維持性能</strong>，無需重新訓練。 → 意涵：訓練一次可跨模型版本使用。</p><hr><h2 id="_2-martian-商業路由器-2023–2026" tabindex="-1">2. Martian（商業路由器，2023–2026） <a class="header-anchor" href="#_2-martian-商業路由器-2023–2026" aria-label="Permalink to &quot;2. Martian（商業路由器，2023–2026）&quot;">​</a></h2><p><strong>來源：</strong> <a href="https://techcrunch.com/2023/11/15/martians-tool-automatically-switches-between-llms-to-reduce-costs/" target="_blank" rel="noreferrer">https://techcrunch.com/2023/11/15/martians-tool-automatically-switches-between-llms-to-reduce-costs/</a></p><h3 id="概況" tabindex="-1">概況 <a class="header-anchor" href="#概況" aria-label="Permalink to &quot;概況&quot;">​</a></h3><ul><li>首個商業 LLM 路由器（2023 年 11 月公開）</li><li>資金：$9M（NEA、General Catalyst、CVP、Prosus Ventures）</li><li>2024 年 9 月：Accenture 投資並採用（企業級部署）</li><li>客戶規模：300+ 公司（Amazon 到 Zapier）</li></ul><h3 id="技術特點" tabindex="-1">技術特點 <a class="header-anchor" href="#技術特點" aria-label="Permalink to &quot;技術特點&quot;">​</a></h3><p>Query-by-query 動態模型選擇；<strong>專利申請中</strong>的路由技術 2025 年新增：AI 模型合規功能（Model Compliance Layer）</p><h3 id="限制" tabindex="-1">限制 <a class="header-anchor" href="#限制" aria-label="Permalink to &quot;限制&quot;">​</a></h3><p>公開量化數字稀少，商業定價不透明。</p><hr><h2 id="_3-routerbench-martian-研究-iclr-2024" tabindex="-1">3. RouterBench（Martian 研究，ICLR 2024） <a class="header-anchor" href="#_3-routerbench-martian-研究-iclr-2024" aria-label="Permalink to &quot;3. RouterBench（Martian 研究，ICLR 2024）&quot;">​</a></h2><p><strong>來源：</strong> <a href="https://github.com/withmartian/routerbench" target="_blank" rel="noreferrer">https://github.com/withmartian/routerbench</a></p><p>多 LLM 路由系統標準化評估基準，由 Martian 維護。 → 對比 RouteLLM 偏學術，RouterBench 偏工業標準化。</p><hr><h2 id="_4-routerarena-開放評估平台" tabindex="-1">4. RouterArena（開放評估平台） <a class="header-anchor" href="#_4-routerarena-開放評估平台" aria-label="Permalink to &quot;4. RouterArena（開放評估平台）&quot;">​</a></h2><p><strong>來源：</strong> <a href="https://arxiv.org/html/2510.00202v1" target="_blank" rel="noreferrer">https://arxiv.org/html/2510.00202v1</a></p><p>類 Chatbot Arena 設計，專門比較不同 LLM 路由器的端到端性能。</p><hr><h2 id="_5-工業界主流路由模式-2025-2026" tabindex="-1">5. 工業界主流路由模式（2025-2026） <a class="header-anchor" href="#_5-工業界主流路由模式-2025-2026" aria-label="Permalink to &quot;5. 工業界主流路由模式（2025-2026）&quot;">​</a></h2><h3 id="_5-1-requesty-企業-llm-路由" tabindex="-1">5.1 Requesty（企業 LLM 路由） <a class="header-anchor" href="#_5-1-requesty-企業-llm-路由" aria-label="Permalink to &quot;5.1 Requesty（企業 LLM 路由）&quot;">​</a></h3><ul><li>側重：上線時間、成本效率、模型選擇</li><li>模式：Intelligent routing + fallback chains</li></ul><h3 id="_5-2-openrouter" tabindex="-1">5.2 OpenRouter <a class="header-anchor" href="#_5-2-openrouter" aria-label="Permalink to &quot;5.2 OpenRouter&quot;">​</a></h3><ul><li>統一 API，自動根據可用性和延遲路由</li><li>功能：provider 切換、fallback、速率限制管理</li></ul><h3 id="_5-3-總結矩陣" tabindex="-1">5.3 總結矩陣 <a class="header-anchor" href="#_5-3-總結矩陣" aria-label="Permalink to &quot;5.3 總結矩陣&quot;">​</a></h3><table tabindex="0"><thead><tr><th>路由器</th><th>類型</th><th>強項</th><th>已知弱點</th></tr></thead><tbody><tr><td>RouteLLM</td><td>開源</td><td>學術驗證、可遷移</td><td>需要偏好訓練數據</td></tr><tr><td>Martian</td><td>商業</td><td>企業合規、scale</td><td>成本不透明</td></tr><tr><td>RouterArena</td><td>評估平台</td><td>標準化比較</td><td>不是路由工具本身</td></tr><tr><td>OpenRouter</td><td>API 層</td><td>高可用性</td><td>不做 query 層路由</td></tr></tbody></table><hr><h2 id="_6-agentopt-限制與批評" tabindex="-1">6. AgentOpt 限制與批評 <a class="header-anchor" href="#_6-agentopt-限制與批評" aria-label="Permalink to &quot;6. AgentOpt 限制與批評&quot;">​</a></h2><h3 id="何時-strong-planner-weak-planner" tabindex="-1">何時 Strong Planner &gt; Weak Planner <a class="header-anchor" href="#何時-strong-planner-weak-planner" aria-label="Permalink to &quot;何時 Strong Planner &gt; Weak Planner&quot;">​</a></h3><p>基於 2025-2026 文獻，以下場景弱規劃器失效：</p><table tabindex="0"><thead><tr><th>場景</th><th>原因</th></tr></thead><tbody><tr><td>順序推理任務</td><td>計劃錯誤無法被求解器修正</td></tr><tr><td>需要全局一致性的複雜邏輯</td><td>弱規劃器缺乏跨步驟視野</td></tr><tr><td>極短 query（&lt;50 tokens）</td><td>分派開銷超過效益</td></tr><tr><td>Domain-specific 高精度任務</td><td>弱模型在 domain 外泛化差</td></tr></tbody></table><h3 id="多代理研究的平行發現-deepmind-2025" tabindex="-1">多代理研究的平行發現（DeepMind 2025） <a class="header-anchor" href="#多代理研究的平行發現-deepmind-2025" aria-label="Permalink to &quot;多代理研究的平行發現（DeepMind 2025）&quot;">​</a></h3><ul><li>4 agents 以上出現「coordination tax」（性能增益飽和）</li><li><strong>45% 規則</strong>：當 single-agent baseline &lt; 45% 時多代理最有效</li><li>當 single-agent &gt; 80%：增加代理<strong>引入噪音而非價值</strong></li></ul><hr><h2 id="知識空白-待後續研究" tabindex="-1">知識空白（待後續研究） <a class="header-anchor" href="#知識空白-待後續研究" aria-label="Permalink to &quot;知識空白（待後續研究）&quot;">​</a></h2><ul><li>[ ] RouterBench 具體評分方法與標準化程度</li><li>[ ] RouteLLM 在非英文任務上的路由準確率</li><li>[ ] Martian 路由的具體算法機制（專利保護）</li><li>[ ] Query 複雜度如何量化（現有方法：embedding similarity、token length、few-shot performance）</li></ul><hr><h2 id="引用來源" tabindex="-1">引用來源 <a class="header-anchor" href="#引用來源" aria-label="Permalink to &quot;引用來源&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2406.18665" target="_blank" rel="noreferrer">RouteLLM Paper (arxiv 2406.18665)</a></li><li><a href="https://www.lmsys.org/blog/2024-07-01-routellm/" target="_blank" rel="noreferrer">RouteLLM LMSYS Blog</a></li><li><a href="https://techcrunch.com/2023/11/15/martians-tool-automatically-switches-between-llms-to-reduce-costs/" target="_blank" rel="noreferrer">Martian TechCrunch</a></li><li><a href="https://newsroom.accenture.com/news/2024/accenture-invests-in-martian-to-bring-dynamic-routing-of-large-language-queries-and-more-effective-ai-systems-to-clients" target="_blank" rel="noreferrer">Accenture × Martian</a></li><li><a href="https://arxiv.org/html/2510.00202v1" target="_blank" rel="noreferrer">RouterArena</a></li><li><a href="https://github.com/withmartian/routerbench" target="_blank" rel="noreferrer">RouterBench GitHub</a></li><li><a href="https://www.swfte.com/blog/intelligent-llm-routing-multi-model-ai" target="_blank" rel="noreferrer">Intelligent LLM Routing 85% cost</a></li></ul>',54)])])}const b=e(l,[["render",o]]);export{g as __pageData,b as default};
